"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[4783],{4701:t=>{t.exports=JSON.parse('{"blogPosts":[{"id":"pagerduty","metadata":{"permalink":"/RSA/blog/pagerduty","source":"@site/blog/collections/pagerduty/pagerduty.mdx","title":"Collections - PagerDuty","description":"Coming Soon","date":"2023-09-02T00:00:00.000Z","formattedDate":"September 2, 2023","tags":[{"label":"Collections","permalink":"/RSA/blog/tags/collections"},{"label":"REST","permalink":"/RSA/blog/tags/rest"},{"label":"ITSM","permalink":"/RSA/blog/tags/itsm"},{"label":"SaaS","permalink":"/RSA/blog/tags/saa-s"},{"label":"Automation","permalink":"/RSA/blog/tags/automation"},{"label":"PagerDuty","permalink":"/RSA/blog/tags/pager-duty"}],"readingTime":10.733333333333333,"hasTruncateMarker":true,"authors":[{"name":"Pradeep Kadambar","title":"Author","url":"https://github.com/pradeepkg","image_url":"https://github.com/pradeepkg.png","imageURL":"https://github.com/pradeepkg.png"}],"frontMatter":{"slug":"pagerduty","title":"Collections - PagerDuty","date":"2023-09-02T00:00:00.000Z","authors":{"name":"Pradeep Kadambar","title":"Author","url":"https://github.com/pradeepkg","image_url":"https://github.com/pradeepkg.png","imageURL":"https://github.com/pradeepkg.png"},"tags":["Collections","REST","ITSM","SaaS","Automation","PagerDuty"]},"nextItem":{"title":"Collections - Tableau","permalink":"/RSA/blog/Tableau"}},"content":"import logoPNG from \'@site/static/img/logos/PagerDuty - 180x180.png\';\\r\\nimport LinkSvg from \'../../iconmonstr-link-thin.svg\';\\r\\n\\r\\n### Coming Soon \\r\\n\\r\\n<table class=\\"table-container\\">\\r\\n  <tr>\\r\\n    <td width=\\"180\\"><img src={logoPNG}/></td>\\r\\n    <td>PagerDuty is a leading digital operations management platform that empowers teams to proactively manage and respond to incidents in real time. By providing actionable insights, automation, and collaboration tools, PagerDuty ensures business continuity and exceptional customer experiences. It centralizes alerts, streamlines incident resolution, and enables teams to work seamlessly across the entire organization, minimizing downtime and optimizing operational efficiency.<br></br><br></br>Identities \u274c | Accounts \u2714\ufe0f | Groups \u2714\ufe0f | App Roles \u2714\ufe0f | Entitlements \u274c</td>\\r\\n  </tr>\\r\\n</table>\\r\\n\\r\\n\x3c!-- truncate --\x3e\\r\\n\\r\\n**Teams** are a way to organize users and objects in PagerDuty. They can be used to control who has access to different objects, such as escalation policies, users, schedules, and services. Teams can also be used to customize the PagerDuty web app by filtering for information relevant to the team\'s associated objects.\\r\\n\\r\\n**User roles** define the level of access that a user has to PagerDuty objects.\\r\\n\\r\\n| Role | Description |\\r\\n| ----------- | ----------- |\\r\\n| admin | Has full access to all objects and configurations in the account. Can create, update, and delete users, teams, schedules, escalation policies, services, and integrations. Can also manage user permissions. |\\r\\n| limited_user | Can view objects and configurations, but cannot make any modifications. |\\r\\n| observer | Can view objects, but cannot make any modifications. |\\r\\n| owner | Has full access to objects and configurations within their team. Can create, update, and delete users, schedules, escalation policies, and services. Can also manage user permissions within their team. |\\r\\n| read_only_user | Can view objects, but cannot make any modifications. |\\r\\n| restricted_access | Can only view incidents and alerts that they are directly involved in. |\\r\\n| read_only_limited_user | Can only view objects that they have been granted access to. |\\r\\n| user | Can view objects and configurations, but cannot make any modifications. |"},{"id":"Tableau","metadata":{"permalink":"/RSA/blog/Tableau","source":"@site/blog/collections/tableau/tableau.md","title":"Collections - Tableau","description":"Tableau is a powerful data visualization tool that transforms complex datasets into interactive and insightful visuals, aiding informed decision-making. Its user-friendly interface enables easy creation of charts, graphs, and dashboards, enhancing data exploration and presentation across various industries and professions.Identities \u274c | Accounts \u2714\ufe0f | Groups \u2714\ufe0f | App Roles \u2714\ufe0f | Entitlements \u274c","date":"2023-08-31T00:00:00.000Z","formattedDate":"August 31, 2023","tags":[{"label":"Collections","permalink":"/RSA/blog/tags/collections"},{"label":"REST","permalink":"/RSA/blog/tags/rest"},{"label":"SaaS","permalink":"/RSA/blog/tags/saa-s"},{"label":"Tableau","permalink":"/RSA/blog/tags/tableau"}],"readingTime":57.03333333333333,"hasTruncateMarker":true,"authors":[{"name":"Pradeep Kadambar","title":"Author","url":"https://github.com/pradeepkg","image_url":"https://github.com/pradeepkg.png","imageURL":"https://github.com/pradeepkg.png"}],"frontMatter":{"slug":"Tableau","title":"Collections - Tableau","date":"2023-08-31T00:00:00.000Z","authors":{"name":"Pradeep Kadambar","title":"Author","url":"https://github.com/pradeepkg","image_url":"https://github.com/pradeepkg.png","imageURL":"https://github.com/pradeepkg.png"},"tags":["Collections","REST","SaaS","Tableau"]},"prevItem":{"title":"Collections - PagerDuty","permalink":"/RSA/blog/pagerduty"},"nextItem":{"title":"Collections - Dynatrace","permalink":"/RSA/blog/dynatrace"}},"content":"import logoPNG from \'@site/static/img/logos/Tableau - 180x180.png\';\\nimport LinkSvg from \'../../iconmonstr-link-thin.svg\';\\n\\n<table class=\\"table-container\\"> \\n  <tr>\\n    <td width=\\"180\\"><img src={logoPNG}/></td>\\n    <td>Tableau is a powerful data visualization tool that transforms complex datasets into interactive and insightful visuals, aiding informed decision-making. Its user-friendly interface enables easy creation of charts, graphs, and dashboards, enhancing data exploration and presentation across various industries and professions.<br></br><br></br>Identities \u274c | Accounts \u2714\ufe0f | Groups \u2714\ufe0f | App Roles \u2714\ufe0f | Entitlements \u274c</td>\\n  </tr>\\n</table>\\n\\n\x3c!-- truncate --\x3e\\n\\nIn Tableau Cloud, users, groups, and site roles are used to control access to content and features.\\n\\n**Users** are individual people who have access to a Tableau Cloud site. Users can be assigned different site roles, which determine what they can do on the site.\\n\\n**Groups** are collections of users. Groups can be used to simplify the process of assigning site roles to multiple users.\\n\\n**Site roles** define the level of access a user has to a Tableau Cloud site. Site roles include:\\n  - **Viewer**: Viewers can view published content, but they cannot create or modify content.\\n  - **Explorer**: Explorers can create and modify content, but they cannot publish content to the site.\\n  - **Creator**: Creators can create, modify, and publish content to the site.\\n  - **Site Administrator Creator**: Site Administrator Creators have all the capabilities of Creators, plus the ability to manage the site\'s users and settings.\\n  - **Site Administrator Explorer**: Site Administrator Explorers have all the capabilities of Explorers, plus the ability to manage the site\'s users and settings.\\n\\n## Table of Contents\\n>\\n- [Application](#application)\\n- [Account Collector](#account-collector)\\n- [Entitlement Collector : Role Members](#entitlement-collector--role-members)\\n- [Application Setup](#application-setup)\\n- [Token Authentication](#token-authentication)\\n- [Custom Web Service : Site Roles](#custom-web-service--site-roles)\\n\\n## Application\\n\\n**Steps**\\n1. Login to RSA G&L console as System Administrator.\\n2. Navigate to **Resources > Application**.\\n3. Click on **Create Application** and select **Other Application**.\\n4. Enter the details as shown below.<br></br>![img](./img/1.png)\\n5. Click **Finish**.\\n---\\n## Account Collector\\nThis section explains the process for configuring an account collector for the Tableau application. We will use the RSA G&L Generic REST collector [^API] for this purpose.  \\n\\n**Steps**\\n1. Login to RSA G&L console as System Administrator.\\n2. Navigate to **Resources > Applications**.\\n3. Click on **Tableau**.\\n4. Navigate to **Collectors** tab and click on **Create Account Collector**. Enter the details as shown below.<br></br><br></br>![img](./img/2.png)\\n5. Click **Next** and enter the connection details.<br></br><br></br>![img](img/3.png)<br></br>The URL contains the site URL https://prod-useast-b.online.tableau.com (for my instance) which needs to be updated to suit your deployment and the site it. ***Site ID*** can be retrieved from the response to the token authentication request.<br></br><br></br>![img](img/3-1.png)\\n6. Click **Next**. Select the data types that the collector will be collecting from Tableau<br></br><br></br>![img](img/4.png)\\n7. Click **Next**. On the **Account Data** page, enter the following configurations.<br></br><br></br>![Alt text](img/5.png)<br></br>![Alt text](img/6.png)<br></br>![Alt text](img/7.png)<br></br>\\n<p align=\\"center\\"></p>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/users</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Query Parameters</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>fields</td>\\n    <td><code>id,email,lastLogin</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Bearer $&#123;AuthenticationToken}</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>AccountId</td>    \\n    <td><code>$.users.*.*.email</code></td>\\n  </tr>\\n  <tr>\\n    <td>Id</td>\\n    <td><code>$.users.*.*.id</code></td>\\n  </tr>    \\n  <tr>\\n    <td>LastLogin</td>\\n    <td><code>$.users.*.*.lastLogin</code></td>\\n  </tr>    \\n</table>\\n<p></p>\\n8. Click **Next**. On the **Group Data** page, enter the following configurations.<br></br><br></br>![Alt text](img/8.png)<br></br>![Alt text](img/6.png)<br></br>![Alt text](img/9.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/groups</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Query Parameters</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>fields</td>\\n    <td><code>id,name</code></td>\\n  </tr>\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr>  \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Bearer $&#123;AuthenticationToken}</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>GroupId</td>    \\n    <td><code>$.groups.*.*.name</code></td>\\n  </tr>\\n  <tr>\\n    <td>Id</td>\\n    <td><code>$.groups.*.*.id</code></td>\\n  </tr>   \\n</table>\\n9. Click **Next**. On the **Account Group Membership**\xa0page, enter the following configurations.<br></br><br></br>![Alt text](img/10.png)<br></br>![Alt text](img/6.png)<br></br>![Alt text](img/11.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/groups/$&#123;Id}/users</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Bearer $&#123;AuthenticationToken}</code></td>\\n  </tr>\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>\\n  <tr>\\n    <td>Account Identifier</td>    \\n    <td><code>$.users.user.*.id</code></td>\\n  </tr>      \\n</table>\\n10. Click\xa0**Next**. In the **Map Collector Attributes to Account Attributes**, map the collected account attributes.<br></br><br></br>![Alt text](img/12.png)\\n11. Click **Next**. In the **Map Collector Attributes to Account Mapping Attributes**, map the user reference attribute.<br></br><br></br>![Alt text](img/13.png)\\n12. Click **Next**. In the **Map Collector Attributes to Group Attributes**, map the collected group attributes.<br></br><br></br>![Alt text](img/14.png)\\n13. Click **Next**. In the **User Resolution Rules**, map the user to account.<br></br><br></br>![Alt text](img/15.png)\\n14. Click **Next**. In the **Member Account Resolution Rules**, map the account.<br></br><br></br>![Alt text](img/16.png)\\n\\n:bulb: **Info:**  This value MUST always be mapped to the Account Name for any generic REST collector.\\n\\n15. Click **Finish**. Use the <code>Test</code> function to make sure the configurations are accurate.\\n\\n---\\n## Entitlement Collector : Role Members\\nThis section explains the process for configuring an entitlement collector to collect site roles and assignments from the Tableau application. We will use the RSA G&L Generic REST collector for this purpose.\\n\\n:::info\\nSince Tableau does not provide an API for listing site roles, we will use a custom web service for the EDC. Refer to [Custom Web Service : Site Roles](#custom-web-service--site-roles) for more information.\\n:::\\n\\n**Steps**\\n1. Login to RSA G&L console as AveksaAdmin.\\n2. Navigate to **Resources > Applications**.\\n3. Click on **Tableau**.\\n4. Navigate to **Collectors** tab and click on ***Create Entitlement Collector***. Enter the details as shown below.<br></br><br></br>![Alt text](img/17.png)\\n5. Click **Next** and enter the connection details as shown in Step 5 of [Account Collector](#account-collector). :bulb: **Note** that the Use Base URL for all API(s) will be unchecked.\\n6. Click **Next**. Select the data types that the collector will be collecting from Tableau.<br></br><br></br>![Alt text](img/18.png)\\n7. Click **Next**. On the **App Role Data** page, enter the following configurations.<br></br><br></br>![Alt text](img/19.png)<br></br>![Alt text](img/6.png)<br></br>![Alt text](img/20.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>https://instance.securid.com/aveksa/custom/external_jsp/TableauSiteRolesv2.jsp</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr>\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>ApplicationRoleId</td>    \\n    <td><code>$.roles.*.role</code></td>\\n  </tr>   \\n  <tr>\\n    <td>Description</td>\\n    <td><code>$.roles.*.description</code></td>\\n  </tr>    \\n</table>\\n8. Click **Next**. On the **App-Role Account Membership** collection page, enter the following configurations.<br></br><br></br>![Alt text](img/20.png)<br></br>![Alt text](img/6.png)<br></br>![Alt text](img/21.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>https://instance.online.tableau.com/api/3.2/sites/SITE_ID/users</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Query Parameters</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>fields</td>\\n    <td><code>id,siteRole</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Bearer $&#123;AuthenticationToken}</code></td>\\n  </tr>\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>Application Role Id</td>    \\n    <td><code>$.users.user.*.siteRole</code></td>\\n  </tr>\\n  <tr>\\n    <td>Account Identifier</td>\\n    <td><code>$.users.user.*.id</code></td>\\n  </tr>    \\n</table>\\n9. Click **Next**. In the **Map Collector Attributes to App Role Attributes**, map the collected account attributes.<br></br>\\n10. Click **Next**. In the **Account Evaluation**, map the account collector to account value.<br></br><br></br>![Alt text](img/26.png)\\n11. Click **Next** and then click **Finish**. Use the <code>Test</code> function to make sure the configurations are accurate\\n\\n---\\n## Application Setup\\nThis section explains the process of setting up Personal Access Token (PAT) in Tableau for use within the collections process.\\n\\n**Steps**\\n1. Login to Tableau site https://instance.online.tableau.com/#/site/SITE/home.\\n2. By default, Personal Access Token (PAT) is disabled.\\n3. Navigate to **Settings** in the navigation panel and click on **General** tab.\\n4. Go to ***Personal Access Tokens*** section and enable PAT.<br></br><br></br>![Alt text](img/25.png)\\n5. Navigate to Users in the navigation panel and click on the user whose PAT needs to be generated.\\n6. Click on Settings tab.\\n7. Go to Personal Access Tokens section. Provide a suitable token name and click Create Token.<br></br><br></br>![Alt text](img/26.png)\\n8. Copy the Secret and click Done.\\n\\n## Token Authentication\\nThis section explains the process of setting up RSA G&L ADC with token authentication.\\n\\n**Steps**\\n1. Login to RSA G&L console as System Administrator.\\n2. Create or Edit a generic REST ADC that will be using **Token** authentication.\\n3. On the **Connection Details** page, configure the following.<br></br><br></br>![Alt text](img/27.png)<br></br>![Alt text](img/28.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-post\\">POST</span></td>\\n  </tr>\\n  <tr>\\n    <td>Token URL</td>\\n    <td><code>\\thttps://YOUR_INSTANCE/api/3.13/auth/signin</code></td>\\n  </tr>  \\n  <tr>\\n    <td>Username</td>\\n    <td>YOUR_PAT_NAME</td>\\n  </tr> \\n  <tr>\\n    <td>Password</td>\\n    <td>YOUR_PAT</td>\\n  </tr>       \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Content-Type</td>\\n    <td><code>application/xml</code></td>\\n  </tr>\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Body</span></td>  \\n  </tr>       \\n  <tr>\\n    <td colspan=\\"2\\">\\n      &lt;?xml version=\\"1.0\\" encoding=\\"UTF-8\\"?&gt;<br />&lt;tsRequest&gt;<br />&lt;credentials personalAccessTokenName=\\"$&#123;TokenUsername}\\" personalAccessTokenSecret=\\"$&#123;TokenPassword}\\"&gt;<br />&lt;site contentUrl=\\"rsaps\\" /&gt;<br />&lt;/credentials&gt;<br />&lt;/tsRequest&gt;\\n    </td> \\n  </tr>    \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>Response Path</td>    \\n    <td><code>$.credentials.token</code></td>\\n  </tr>    \\n</table>\\n4. Save the collector configuration & test.\\n\\n## Custom Web Service : Site Roles\\nSince Tableau does not provide an API for listing site roles, we will use a custom JSP that will publish the site roles. \\n\\n**Steps**\\n1. Open a text editor and save the contents below as <code>TableauSiteRolesv2.jsp.</code>\\n```jsp\\n<%@ page language=\\"java\\" contentType=\\"application/json\\" %>\\n<%\\n    String jsonData = \\"{\\"\\n        + \\"\\\\\\"roles\\\\\\": [\\"\\n        + \\"{\\\\\\"role\\\\\\":\\\\\\"Creator\\\\\\",\\\\\\"description\\\\\\":\\\\\\"Users with this role can create and publish content such as workbooks and data sources on the Tableau site.\\\\\\"},\\"\\n        + \\"{\\\\\\"role\\\\\\":\\\\\\"Explorer\\\\\\",\\\\\\"description\\\\\\":\\\\\\"Users assigned as Explorers can interact with and explore content on the Tableau site. They can view and interact with dashboards and reports but do not have the ability to create or publish new content.\\\\\\"},\\"\\n        + \\"{\\\\\\"role\\\\\\":\\\\\\"ExplorerCanPublish\\\\\\",\\\\\\"description\\\\\\":\\\\\\"Similar to the \\\\\\\\\\\\\\"Explorer\\\\\\\\\\\\\\" role, users with this role can explore content on the site. Additionally, they have the ability to create and publish their own content.\\\\\\"},\\"\\n        + \\"{\\\\\\"role\\\\\\":\\\\\\"ServerAdministrator\\\\\\",\\\\\\"description\\\\\\":\\\\\\"Users with this role have full administrative control over the entire Tableau Server. They can manage users, groups, projects, data sources, and server-wide settings.\\\\\\"},\\"\\n        + \\"{\\\\\\"role\\\\\\":\\\\\\"SiteAdministratorExplorer\\\\\\",\\\\\\"description\\\\\\":\\\\\\"Site Administrators have full control over a specific site. For the Explorer role, this means they can manage users, content, and site-specific settings.\\\\\\"},\\"\\n        + \\"{\\\\\\"role\\\\\\":\\\\\\"SiteAdministratorCreator\\\\\\",\\\\\\"description\\\\\\":\\\\\\"Similar to SiteAdministratorExplorer, Site Administrators with the Creator role can manage users, content, and site settings. They also have the ability to create new content.\\\\\\"},\\"\\n        + \\"{\\\\\\"role\\\\\\":\\\\\\"Unlicensed\\\\\\",\\\\\\"description\\\\\\":\\\\\\"Users assigned this role do not have access to content on the Tableau site. It is typically used for users who do not need access to Tableau resources.\\\\\\"},\\"\\n        + \\"{\\\\\\"role\\\\\\":\\\\\\"ReadOnly\\\\\\",\\\\\\"description\\\\\\":\\\\\\"Users with this role can view content on the Tableau site but do not have the ability to interact with or modify it. They can consume dashboards and reports without making changes.\\\\\\"},\\"\\n        + \\"{\\\\\\"role\\\\\\":\\\\\\"Viewer\\\\\\",\\\\\\"description\\\\\\":\\\\\\"Similar to the ReadOnly role, Viewers can view and interact with content on the Tableau site, but they also have the ability to make changes to views and save personal copies of them.\\\\\\"}\\"\\n        + \\"]\\"\\n        + \\"}\\";\\n%>\\n\\n<%\\n    response.setContentType(\\"application/json\\");\\n    out.print(jsonData);\\n%>\\n```\\n2. Login to RSA G&L console as AveksaAdmin.\\n3. Navigate to ***Admin > User Interface.***\\n4. Click on ***Files***.\\n5. Select External JSP Pages and click on ***Upload***.\\n6. Select the <code>TableauSiteRolesv2.jsp</code> and click ***OK***.\\n7. Verify by accessing this URL in the browser https://instance.securid.com/aveksa/custom/external_jsp/TableauSiteRolesv2.jsp \\n\\n[^API]: <LinkSvg /><a href=\\"https://Tableau.dev/apis\\" target=\\"_blank\\">Tableau APIs</a>"},{"id":"dynatrace","metadata":{"permalink":"/RSA/blog/dynatrace","source":"@site/blog/collections/dynatrace/dynatrace.md","title":"Collections - Dynatrace","description":"Dynatrace is a software intelligence company that specializes in application performance management (APM) and observability solutions for modern cloud environments. Its platform provides real-time insights into the performance of applications and the underlying infrastructure that supports them. Dynatrace\'s primary goal is to help organizations ensure the optimal functioning of their digital services and applications, especially in complex and dynamic environments.Identities \u274c | Accounts \u2714\ufe0f | Groups \u2714\ufe0f | App Roles \u274c | Entitlements \u274c","date":"2023-08-30T00:00:00.000Z","formattedDate":"August 30, 2023","tags":[{"label":"Collections","permalink":"/RSA/blog/tags/collections"},{"label":"REST","permalink":"/RSA/blog/tags/rest"},{"label":"SaaS","permalink":"/RSA/blog/tags/saa-s"},{"label":"Monitoring","permalink":"/RSA/blog/tags/monitoring"},{"label":"APM","permalink":"/RSA/blog/tags/apm"},{"label":"Dynatrace","permalink":"/RSA/blog/tags/dynatrace"}],"readingTime":25.666666666666668,"hasTruncateMarker":true,"authors":[{"name":"Pradeep Kadambar","title":"Author","url":"https://github.com/pradeepkg","image_url":"https://github.com/pradeepkg.png","imageURL":"https://github.com/pradeepkg.png"}],"frontMatter":{"slug":"dynatrace","title":"Collections - Dynatrace","date":"2023-08-30T00:00:00.000Z","authors":{"name":"Pradeep Kadambar","title":"Author","url":"https://github.com/pradeepkg","image_url":"https://github.com/pradeepkg.png","imageURL":"https://github.com/pradeepkg.png"},"tags":["Collections","REST","SaaS","Monitoring","APM","Dynatrace"]},"prevItem":{"title":"Collections - Tableau","permalink":"/RSA/blog/Tableau"},"nextItem":{"title":"Collections - PingOne","permalink":"/RSA/blog/pingone"}},"content":"import logoPNG from \'@site/static/img/logos/Dynatrace - 180x180.png\';\\nimport LinkSvg from \'../../iconmonstr-link-thin.svg\';\\n\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td width=\\"180\\"><img src={logoPNG}/></td>\\n    <td>Dynatrace is a software intelligence company that specializes in application performance management (APM) and observability solutions for modern cloud environments. Its platform provides real-time insights into the performance of applications and the underlying infrastructure that supports them. Dynatrace\'s primary goal is to help organizations ensure the optimal functioning of their digital services and applications, especially in complex and dynamic environments.<br></br><br></br>Identities \u274c | Accounts \u2714\ufe0f | Groups \u2714\ufe0f | App Roles \u274c | Entitlements \u274c</td>\\n  </tr>\\n</table>\\n\\n\x3c!-- truncate --\x3e\\n\\n## Table of Contents\\n>\\n- [Application](#application)\\n- [Account Collector](#account-collector)\\n- [Application Setup](#application-setup)\\n- [Token Authentication](#token-authentication)\\n\\n## Application\\n\\n**Steps**\\n1. Login to RSA G&L console as System Administrator.\\n2. Navigate to **Resources > Application**.\\n3. Click on **Create Application** and select **Other Application**.\\n4. Enter the details as shown below.<br></br>![img](./img/1.png)\\n5. Click **Finish**.\\n---\\n## Account Collector\\nThis section explains the process for configuring an account collector for the Dynatrace application. We will use the RSA G&L Generic REST collector [^API] for this purpose.  \\n\\n**Steps**\\n1. Login to RSA G&L console as System Administrator.\\n2. Navigate to **Resources > Applications**.\\n3. Click on **Dynatrace**.\\n4. Navigate to **Collectors** tab and click on **Create Account Collector**. Enter the details as shown below.<br></br><br></br>![img](./img/2.png)\\n5. Click **Next** and enter the connection details. Refer to [Token Authentication](#token-authentication) for more information on authentication configuration.<br></br><br></br>![img](img/3.png)\\n6. Click **Next**. Select the data types that the collector will be collecting from Dynatrace<br></br><br></br>![img](img/4.png)\\n7. Click **Next**. On the **Account Data** page, enter the following configurations.<br></br><br></br>![Alt text](img/5.png)<br></br>![Alt text](img/7.png)<br></br>\\n<p align=\\"center\\"></p>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/users</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Bearer $&#123;AuthenticationToken}</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>AccountId</td>    \\n    <td><code>$.items.*.email</code></td>\\n  </tr>\\n  <tr>\\n    <td>Id</td>\\n    <td><code>$.items.*.uid</code></td>\\n  </tr>    \\n  <tr>\\n    <td>UserStatus</td>\\n    <td><code>$.items.*.userStatus</code></td>\\n  </tr>      \\n  <tr>\\n    <td>LastLogin</td>\\n    <td><code>$.items.*.userLoginMetadata.lastSuccessfulLogin</code></td>\\n  </tr>   \\n</table>\\n<p></p>\\n8. Click **Next**. On the **Group Data** page, enter the following configurations.<br></br><br></br>![Alt text](img/8.png)<br></br>![Alt text](img/9.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/groups</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Bearer $&#123;AuthenticationToken}</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>GroupId</td>    \\n    <td><code>$.items.*.name</code></td>\\n  </tr>\\n  <tr>\\n    <td>Id</td>\\n    <td><code>$.items.*.uuid</code></td>\\n  </tr>    \\n  <tr>\\n    <td>Description</td>\\n    <td><code>$.items.*.description</code></td>\\n  </tr>    \\n</table>\\n9. Click **Next**. On the **Account Group Membership**\xa0page, enter the following configurations.<br></br><br></br>![Alt text](img/10.png)<br></br>![Alt text](img/11.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/groups/$&#123;Id}/users</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Bearer $&#123;AuthenticationToken}</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>Account Identifier</td>    \\n    <td><code>$.data.*.id</code></td>\\n  </tr>    \\n</table>\\n10. Click\xa0**Next**. In the **Map Collector Attributes to Account Attributes**, map the collected account attributes.<br></br><br></br>![Alt text](img/12.png)\\n11. Click **Next**. In the **Map Collector Attributes to Account Mapping Attributes**, map the user reference attribute.<br></br><br></br>![Alt text](img/13.png)\\n12. Click **Next**. In the **Map Collector Attributes to Group Attributes**, map the collected group attributes.<br></br><br></br>![Alt text](img/14.png)\\n13. Click **Next**. In the **User Resolution Rules**, map the user to account.<br></br><br></br>![Alt text](img/15.png)\\n14. Click **Next**. In the **Member Account Resolution Rules**, map the account.<br></br><br></br>![Alt text](img/16.png)\\n\\n:bulb: **Info:**  This value MUST always be mapped to the Account Name for any generic REST collector.\\n\\n15. Click **Finish**. Use the <code>Test</code> function to make sure the configurations are accurate.\\n\\n---\\n## Application Setup\\nThis section explains the process of setting up a service account in Dynatrace for use within the collections process.\\n\\n**Steps**\\n1. Login to Dynatrace Account Management console https://myaccount.dynatrace.com/account/home.\\n2. Under Identity & access management, click on OAuth clients.<br></br><br></br>![Alt text](img/17.png)\\n3. Click on Create client.<br></br><br></br>![Alt text](img/18.png)\\n4. Provide a valid (existing / Active) user email address and a meaningful description. We will restrict permissions to view user and groups data.<br></br><br></br>![Alt text](img/19.png)\\n5. Click Create client.<br></br><br></br>![Alt text](img/20.png)\\n6. Copy the client ID, client secret and account ID (portion after <code>urn:daccount:</code>).\\n\\n## Token Authentication\\nThis section explains the process of setting up RSA G&L ADC with token authentication.\\n\\n**Steps**\\n1. Login to RSA G&L console as System Administrator.\\n2. Create or Edit a generic REST ADC that will be using **Token** authentication.\\n3. On the **Connection Details** page, configure the following.<br></br><br></br>![Alt text](img/21.png)<br></br>![Alt text](img/22.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-post\\">POST</span></td>\\n  </tr>\\n  <tr>\\n    <td>Token URL</td>\\n    <td><code>https://sso.dynatrace.com/sso/oauth2/token</code></td>\\n  </tr>  \\n  <tr>\\n    <td>Username</td>\\n    <td>Client ID</td>\\n  </tr> \\n  <tr>\\n    <td>Password</td>\\n    <td>Client Secret</td>\\n  </tr>       \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Content-Type</td>\\n    <td><code>application/x-www-form-urlencoded</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Body</span></td>  \\n  </tr>       \\n  <tr>\\n    <td colspan=\\"2\\">grant_type=client_credentials&client_id=$&#123;TokenUsername}&client_secret=$&#123;TokenPassword}&scope=account-idm-read</td> \\n  </tr>    \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>Response Path</td>    \\n    <td><code>$.access_token</code></td>\\n  </tr>    \\n</table>\\n4. Save the collector configuration & test.\\n \\n\\n[^API]: <LinkSvg /><a href=\\"https://www.dynatrace.com/support/help/dynatrace-api\\" target=\\"_blank\\">Dynatrace API</a>"},{"id":"pingone","metadata":{"permalink":"/RSA/blog/pingone","source":"@site/blog/collections/pingone/pingone.md","title":"Collections - PingOne","description":"PingOne is an identity and access management (IAM) solution by Ping Identity. It offers secure user authentication, authorization, and single sign-on across applications. With advanced features like multifactor authentication and adaptive security, PingOne ensures streamlined access control while enhancing user experience and safeguarding sensitive data.Identities \u274c | Accounts \u2714\ufe0f | Groups \u2714\ufe0f | App Roles \u274c | Entitlements \u274c","date":"2023-08-28T00:00:00.000Z","formattedDate":"August 28, 2023","tags":[{"label":"Collections","permalink":"/RSA/blog/tags/collections"},{"label":"REST","permalink":"/RSA/blog/tags/rest"},{"label":"SSO","permalink":"/RSA/blog/tags/sso"},{"label":"IAM","permalink":"/RSA/blog/tags/iam"},{"label":"SaaS","permalink":"/RSA/blog/tags/saa-s"},{"label":"MFA","permalink":"/RSA/blog/tags/mfa"},{"label":"PingOne","permalink":"/RSA/blog/tags/ping-one"},{"label":"PingIdentity","permalink":"/RSA/blog/tags/ping-identity"}],"readingTime":30.3,"hasTruncateMarker":true,"authors":[{"name":"Pradeep Kadambar","title":"Author","url":"https://github.com/pradeepkg","image_url":"https://github.com/pradeepkg.png","imageURL":"https://github.com/pradeepkg.png"}],"frontMatter":{"slug":"pingone","title":"Collections - PingOne","date":"2023-08-28T00:00:00.000Z","authors":{"name":"Pradeep Kadambar","title":"Author","url":"https://github.com/pradeepkg","image_url":"https://github.com/pradeepkg.png","imageURL":"https://github.com/pradeepkg.png"},"tags":["Collections","REST","SSO","IAM","SaaS","MFA","PingOne","PingIdentity"]},"prevItem":{"title":"Collections - Dynatrace","permalink":"/RSA/blog/dynatrace"},"nextItem":{"title":"Collections - Qlik","permalink":"/RSA/blog/qlik"}},"content":"import logoPNG from \'@site/static/img/logos/Ping Identity - 180x180.png\';\\nimport LinkSvg from \'../../iconmonstr-link-thin.svg\';\\n\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td width=\\"180\\"><img src={logoPNG}/></td>\\n    <td>PingOne is an identity and access management (IAM) solution by Ping Identity. It offers secure user authentication, authorization, and single sign-on across applications. With advanced features like multifactor authentication and adaptive security, PingOne ensures streamlined access control while enhancing user experience and safeguarding sensitive data.<br></br><br></br>Identities \u274c | Accounts \u2714\ufe0f | Groups \u2714\ufe0f | App Roles \u274c | Entitlements \u274c</td>\\n  </tr>\\n</table>\\n\\n\x3c!-- truncate --\x3e\\n\\n## Table of Contents\\n>\\n- [Application](#application)\\n- [Account Collector](#account-collector)\\n- [Application Setup](#application-setup)\\n- [Token Authentication](#token-authentication)\\n\\n## Application\\n\\n**Steps**\\n1. Login to RSA G&L console as System Administrator.\\n2. Navigate to **Resources > Application**.\\n3. Click on **Create Application** and select **Other Application**.\\n4. Enter the details as shown below.<br></br>![img](./img/1.png)\\n5. Click **Finish**.\\n---\\n## Account Collector\\nThis section explains the process for configuring an account collector for the PingOne application. We will use the RSA G&L Generic REST collector [^API] for this purpose.  \\n\\n**Steps**\\n1. Login to RSA G&L console as System Administrator.\\n2. Navigate to **Resources > Applications**.\\n3. Click on **PingOne**.\\n4. Navigate to **Collectors** tab and click on **Create Account Collector**. Enter the details as shown below.<br></br><br></br>![img](./img/2.png)\\n5. Click **Next** and enter the connection details. PingOne supports both OAuth and API key based authentication. We will token authentication for our collectors in this article.  Refer to [Token Authentication](#token-authentication) section.<br></br><br></br>![img](img/3.png)\\n6. Click **Next**. Select the data types that the collector will be collecting from PingOne<br></br><br></br>![img](img/4.png)\\n7. Click **Next**. On the **Account Data** page, enter the following configurations.<br></br><br></br>![Alt text](img/5.png)<br></br>![Alt text](img/7.png)<br></br>\\n<p align=\\"center\\"></p>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/users</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Bearer $&#123;AuthenticationToken}</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>AccountId</td>    \\n    <td><code>$._embedded.users.*.email</code></td>\\n  </tr>\\n  <tr>\\n    <td>Id</td>\\n    <td><code>$._embedded.users.*.id</code></td>\\n  </tr>    \\n  <tr>\\n    <td>Status</td>\\n    <td><code>$._embedded.users.*.verifyStatus</code></td>\\n  </tr>      \\n  <tr>\\n    <td>IsEnabled</td>\\n    <td><code>$._embedded.users.*.enabled</code></td>\\n  </tr>  \\n  <tr>\\n    <td>UserName</td>\\n    <td><code>$._embedded.users.*.username</code></td>\\n  </tr>    \\n</table>\\n<p></p>\\n8. Click **Next**. On the **Group Data** page, enter the following configurations.<br></br><br></br>![Alt text](img/8.png)<br></br>![Alt text](img/9.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/groups</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Bearer $&#123;AuthenticationToken}</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>GroupId</td>    \\n    <td><code>$._embedded.groups.*.name</code></td>\\n  </tr>\\n  <tr>\\n    <td>Id</td>\\n    <td><code>$._embedded.groups.*.id</code></td>\\n  </tr>    \\n  <tr>\\n    <td>Description</td>\\n    <td><code>$._embedded.groups.*.description</code></td>\\n  </tr>     \\n  <tr>\\n    <td>Owner</td>\\n    <td><code>$._embedded.groups.*.customData.groupOwner</code></td>\\n  </tr>   \\n</table>\\n9. Click **Next**. On the **Account Group Membership**\xa0page, enter the following configurations.<br></br><br></br>![Alt text](img/10.png)<br></br>![Alt text](img/11.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/users/$&#123;Id}</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Query Parameters</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>include</td>\\n    <td><code>memberOfGroupIDs</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Bearer $&#123;AuthenticationToken}</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>Group Identifier</td>    \\n    <td><code>$.memberOfGroupIDs.*</code></td>\\n  </tr>    \\n</table>\\n10. Click **Next**. On the **Subgroup Membership** page, enter the following configurations.<br></br><br></br>![Alt text](img/12.png)<br></br>![Alt text](img/13.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/groups/$&#123;Id}/memberOfGroups</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Bearer $&#123;AuthenticationToken}</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>Subgroup Identifier</td>    \\n    <td><code>$._embedded.groupMemberships.*.id</code></td>\\n  </tr>    \\n</table>\\n11. Click\xa0**Next**. In the **Map Collector Attributes to Account Attributes**, map the collected account attributes.<br></br><br></br>![Alt text](img/14.png)\\n12. Click **Next**. In the **Map Collector Attributes to Account Mapping Attributes**, map the user reference attribute.<br></br><br></br>![Alt text](img/15.png)\\n13. Click **Next**. In the **Map Collector Attributes to Group Attributes**, map the collected group attributes.<br></br><br></br>![Alt text](img/16.png)\\n14. Click **Next**. In the **User Resolution Rules**, map the user to account.<br></br><br></br>![Alt text](img/17.png)\\n15. Click **Next**. In the **Member Account Resolution Rules**, map the account attribute.<br></br><br></br>![Alt text](img/18.png)\\n16. Click **Next**. In the **Sub-group Resolution Rules**, map the group attribute.<br></br><br></br>![Alt text](img/19.png)\\n17. Click **Next**. In the **Group Owner Resolution Rules**, map the group attribute.<br></br><br></br>![Alt text](img/20.png)\\n18. Click **Finish**. Use the <code>Test</code> function to make sure the configurations are accurate.\\n\\n---\\n## Application Setup\\nThis section explains the process of setting up a service account in PingOne for use within the collections process.\\n\\n**Steps**\\n1. Login to PingOne console https://console.pingone.com/index.html \\n2. Navigate to **Connections > Applications**.<br></br><br></br>![Alt text](img/21.png)\\n3. Click on **Add Applications**.<br></br><br></br>![Alt text](img/22.png)\\n4. Enter a suitable name and description and select application type as ***Worker***.<br></br><br></br>![Alt text](img/23.png)\\n5. Click on **Save**.\\n6. Click on the toggle to enable the application. Click on **Grant Roles** to add the necessary roles for the integration account.<br></br><br></br>![Alt text](img/24.png)\\n7. Add ***Identity Data Read Only Permissions*** roles and click **Save**.<br></br><br></br>![Alt text](img/25.png)\\n8. Click on **Configuration** tab and copy the Client ID and Client Secret.<br></br><br></br>![Alt text](img/26.png)\\n\\n## Token Authentication\\nThis section explains the process of setting up RSA G&L ADC with token authentication.\\n\\n**Steps**\\n1. Login to RSA G&L console as System Administrator.\\n2. Create or Edit a generic REST ADC that will be using **Token** authentication.\\n3. On the **Connection Details** page, configure the following.<br></br><br></br>![Alt text](img/27.png)<br></br>![Alt text](img/28.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-post\\">POST</span></td>\\n  </tr>\\n  <tr>\\n    <td>Token URL</td>\\n    <td><code>https://auth.pingone.com/YOUR_ENV_ID/as/token</code></td>\\n  </tr>  \\n  <tr>\\n    <td>Username</td>\\n    <td>NA</td>\\n  </tr> \\n  <tr>\\n    <td>Password</td>\\n    <td>NA</td>\\n  </tr>       \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Content-Type</td>\\n    <td><code>application/x-www-form-urlencoded</code></td>\\n  </tr>  \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Basic AUTH_STRING</code><br></br><br></br>AUTH_STRING - The Base64 encoded string of <code>Client_ID:Client_Secret</code>. The REST API to get the token requires basic authentication to be setup, instead of standard practice of sending the credentials in the POST body.</td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Body</span></td>  \\n  </tr>       \\n  <tr>\\n    <td colspan=\\"2\\">grant_type=client_credentials</td> \\n  </tr>    \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>Response Path</td>    \\n    <td><code>$.access_token</code></td>\\n  </tr>    \\n</table>\\n4. Save the collector configuration & test.\\n \\n\\n[^API]: <LinkSvg /><a href=\\"https://www.PingOne.com/support/help/PingOne-api\\" target=\\"_blank\\">PingOne API</a>"},{"id":"qlik","metadata":{"permalink":"/RSA/blog/qlik","source":"@site/blog/collections/qlik/qlik.md","title":"Collections - Qlik","description":"A Qlik application is a powerful data analytics tool that enables users to visualize and explore data for insightful decision-making. It facilitates interactive data discovery, real-time analysis, and dynamic dashboards. Qlik applications offer a user-friendly interface to create, manipulate, and share data-driven insights, fostering better understanding of trends and patterns within data.Identities \u274c | Accounts \u2714\ufe0f | Groups \u2714\ufe0f | App Roles \u2714\ufe0f | Entitlements \u274c","date":"2023-08-27T00:00:00.000Z","formattedDate":"August 27, 2023","tags":[{"label":"Collections","permalink":"/RSA/blog/tags/collections"},{"label":"REST","permalink":"/RSA/blog/tags/rest"},{"label":"SaaS","permalink":"/RSA/blog/tags/saa-s"},{"label":"Qlik","permalink":"/RSA/blog/tags/qlik"}],"readingTime":41.36666666666667,"hasTruncateMarker":true,"authors":[{"name":"Pradeep Kadambar","title":"Author","url":"https://github.com/pradeepkg","image_url":"https://github.com/pradeepkg.png","imageURL":"https://github.com/pradeepkg.png"}],"frontMatter":{"slug":"qlik","title":"Collections - Qlik","date":"2023-08-27T00:00:00.000Z","authors":{"name":"Pradeep Kadambar","title":"Author","url":"https://github.com/pradeepkg","image_url":"https://github.com/pradeepkg.png","imageURL":"https://github.com/pradeepkg.png"},"tags":["Collections","REST","SaaS","Qlik"]},"prevItem":{"title":"Collections - PingOne","permalink":"/RSA/blog/pingone"},"nextItem":{"title":"Collections - Freshservice","permalink":"/RSA/blog/freshservice"}},"content":"import logoPNG from \'@site/static/img/logos/Qlik - 180x180.png\';\\nimport LinkSvg from \'../../iconmonstr-link-thin.svg\';\\n\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td width=\\"180\\"><img src={logoPNG}/></td>\\n    <td>A Qlik application is a powerful data analytics tool that enables users to visualize and explore data for insightful decision-making. It facilitates interactive data discovery, real-time analysis, and dynamic dashboards. Qlik applications offer a user-friendly interface to create, manipulate, and share data-driven insights, fostering better understanding of trends and patterns within data.<br></br><br></br>Identities \u274c | Accounts \u2714\ufe0f | Groups \u2714\ufe0f | App Roles \u2714\ufe0f | Entitlements \u274c</td>\\n  </tr>\\n</table>\\n\\n\x3c!-- truncate --\x3e\\n\\n**Users** are individuals who interact with Qlik applications to analyze, visualize, and gain insights from data. Each user has a unique account and login credentials to access the application. Users can have different roles and permissions based on their responsibilities within the organization.\\n\\n**Groups** are collections of users who share similar roles or responsibilities. They enable efficient management of permissions and access control. Users within the same group often require the same level of access to data and functionalities. Grouping users simplifies administration and ensures consistency in permissions.\\n\\n**Roles** define specific sets of permissions that determine what actions users can perform within the application. Roles can include privileges like creating, editing, or deleting data, as well as administrative capabilities. By assigning roles to users or groups, organizations ensure that users have the appropriate level of access and functionality based on their roles or responsibilities.\\n\\nIn Qlik applications, users are typically organized into groups. Roles are then assigned to these groups to define the permissions and actions that users within the group can undertake. This hierarchical approach streamlines access management: by modifying roles assigned to a group, permissions are automatically adjusted for all users within that group. This ensures data security, simplifies access control, and maintains consistency in permissions across the organization.\\n\\n## Table of Contents\\n>\\n- [Application](#application)\\n- [Account Collector](#account-collector)\\n- [Entitlement Collector](#entitlement-collector)\\n- [Application Setup](#application-setup)\\n\\n## Application\\n\\n**Steps**\\n1. Login to RSA G&L console as System Administrator.\\n2. Navigate to **Resources > Application**.\\n3. Click on **Create Application** and select **Other Application**.\\n4. Enter the details as shown below.<br></br>![img](./img/1.png)\\n5. Click **Finish**.\\n---\\n## Account Collector\\nThis section explains the process for configuring an account collector for the Qlik application. We will use the RSA G&L Generic REST collector [^API] for this purpose.  \\n\\n**Steps**\\n1. Login to RSA G&L console as System Administrator.\\n2. Navigate to **Resources > Applications**.\\n3. Click on **Qlik**.\\n4. Navigate to **Collectors** tab and click on **Create Account Collector**. Enter the details as shown below.<br></br><br></br>![img](./img/2.png)\\n5. Click **Next** and enter the connection details. <br></br><br></br>![img](img/3.png)\\n6. Click **Next**. Select the data types that the collector will be collecting from Qlik<br></br><br></br>![img](img/4.png)\\n7. Click **Next**. On the **Account Data** page, enter the following configurations.<br></br><br></br>![Alt text](img/5.png)<br></br>![Alt text](img/6.png)<br></br>![Alt text](img/7.png)<br></br>\\n<p align=\\"center\\"></p>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/api/v1/users</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Query Parameters</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>fields</td>\\n    <td><code>id,email,status</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Bearer $&#123;AuthenticationToken}</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>AccountId</td>    \\n    <td><code>$.data.*.email</code></td>\\n  </tr>\\n  <tr>\\n    <td>Id</td>\\n    <td><code>$.data.*.id</code></td>\\n  </tr>    \\n  <tr>\\n    <td>Status</td>\\n    <td><code>$.data.*.status</code></td>\\n  </tr>    \\n</table>\\n<p></p>\\n8. Click **Next**. On the **Group Data** page, enter the following configurations.<br></br><br></br>![Alt text](img/8.png)<br></br>![Alt text](img/6.png)<br></br>![Alt text](img/9.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/api/v1/groups</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr>  \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Bearer $&#123;AuthenticationToken}</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>GroupId</td>    \\n    <td><code>$.data.*.name</code></td>\\n  </tr>\\n  <tr>\\n    <td>Id</td>\\n    <td><code>$.data.*.id</code></td>\\n  </tr>    \\n  <tr>\\n    <td>Status</td>\\n    <td><code>$.data.*.status</code></td>\\n  </tr>    \\n</table>\\n9. Click **Next**. On the **Account Group Membership**\xa0page, enter the following configurations.<br></br><br></br>![Alt text](img/10.png)<br></br>![Alt text](img/6.png)<br></br>![Alt text](img/11.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/api/v1/users</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Query Parameters</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>fields</td>\\n    <td><code>id,assignedGroups</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Bearer $&#123;AuthenticationToken}</code></td>\\n  </tr>\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>\\n  <tr>\\n    <td>Account Identifier</td>    \\n    <td><code>$.data.*.id</code></td>\\n  </tr> \\n  <tr>\\n    <td>Group Identifier</td>    \\n    <td><code>Group Identifier\\t$.data.*.assignedGroups.*.id</code></td>\\n  </tr>       \\n</table>\\n10. Click\xa0**Next**. In the **Map Collector Attributes to Account Attributes**, map the collected account attributes.<br></br><br></br>![Alt text](img/12.png)\\n11. Click **Next**. In the **Map Collector Attributes to Account Mapping Attributes**, map the user reference attribute.<br></br><br></br>![Alt text](img/13.png)\\n12. Click **Next**. In the **Map Collector Attributes to Group Attributes**, map the collected group attributes.<br></br><br></br>![Alt text](img/14.png)\\n13. Click **Next**. In the **User Resolution Rules**, map the user to account.<br></br><br></br>![Alt text](img/15.png)\\n14. Click **Next**. In the **Member Account Resolution Rules**, map the account.<br></br><br></br>![Alt text](img/16.png)\\n\\n:bulb: **Info:**  This value MUST always be mapped to the Account Name for any generic REST collector.\\n\\n15. Click **Finish**. Use the <code>Test</code> function to make sure the configurations are accurate.\\n\\n---\\n## Entitlement Collector\\nThis section explains the process for configuring an entitlement collector to collect roles from Qlik application. We will use the RSA G&L Generic REST collector for this purpose.\\n\\n**Steps**\\n1. Login to RSA G&L console as AveksaAdmin.\\n2. Navigate to **Resources > Applications**.\\n3. Click on **Qlik**.\\n4. Navigate to **Collectors** tab and click on ***Create Entitlement Collector***. Enter the details as shown below.<br></br><br></br>![Alt text](img/17.png)\\n5. Click **Next** and enter the connection details as shown in Step 5 of [Account Collector](#account-collector).\\n6. Click **Next**. Select the data types that the collector will be collecting from Qlik.<br></br><br></br>![Alt text](img/18.png)\\n7. Click **Next**. On the **App Role Data** page, enter the following configurations.<br></br><br></br>![Alt text](img/19.png)<br></br>![Alt text](img/6.png)<br></br>![Alt text](img/20.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/api/v1/roles</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Bearer $&#123;AuthenticationToken}</code></td>\\n  </tr>\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>ApplicationRoleId</td>    \\n    <td><code>$.data.*.name</code></td>\\n  </tr>\\n  <tr>\\n    <td>Id</td>\\n    <td><code>$.data.*.id</code></td>\\n  </tr>    \\n  <tr>\\n    <td>Description</td>\\n    <td><code>$.data.*.description</code></td>\\n  </tr>    \\n</table>\\n8. Click **Next**. On the **App-Role Account Membership** collection page, enter the following configurations.<br></br><br></br>![Alt text](img/20.png)<br></br>![Alt text](img/6.png)<br></br>![Alt text](img/21.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/api/v1/users</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Query Parameters</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>fields</td>\\n    <td><code>id,assignedRoles</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Bearer $&#123;AuthenticationToken}</code></td>\\n  </tr>\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>Application Role Id</td>    \\n    <td><code>$.data.*.assignedRoles.*.id</code></td>\\n  </tr>\\n  <tr>\\n    <td>Account Identifier</td>\\n    <td><code>$.data.*.id</code></td>\\n  </tr>    \\n</table>\\n9. Click **Next**. On the **App-Role Group Membership Data** page, enter the following configurations.<br></br><br></br>![Alt text](img/22.png)<br></br>![Alt text](img/6.png)<br></br>![Alt text](img/23.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/api/v1/groups</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td>Authorization</td>\\n    <td><code>Bearer $&#123;AuthenticationToken}</code></td>\\n  </tr>\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>Application Role Id</td>    \\n    <td><code>$.data.*.assignedRoles.*.id</code></td>\\n  </tr>\\n  <tr>\\n    <td>Account Identifier</td>\\n    <td><code>$.data.*.id</code></td>\\n  </tr>   \\n</table>\\n10. Click **Next**. On the **App-Role Account Membership** collection page, enter the following configurations.<br></br><br></br>![Alt text](img/24.png)<br></br>![Alt text](img/6.png)<br></br>![Alt text](img/25.png)<br></br>\\n11. Click **Next**. In the **Map Collector Attributes to App Role Attributes**, map the collected account attributes.<br></br>\\n12. Click **Next**. In the **Account Evaluation**, map the account collector to account value.<br></br><br></br>![Alt text](img/26.png)\\n13. Click **Next** and then click **Finish**. Use the <code>Test</code> function to make sure the configurations are accurate\\n\\n---\\n## Application Setup\\nThis section explains the process of setting up a service account in Qlik for use within the collections process.\\n\\n**Steps**\\n1. Login to Qlik Management console https://instance.qlikcloud.com/console/home.\\n2. By default, API keys are disabled. Navigate to **Settings** and, under **API Keys**, select *Enable API Keys*.<br></br><br></br>![Alt text](img/27.png)\\n3. Navigate to **API Keys** and click on **Generate New**.\\n4. Click on **Generate New Key**.\\n5. Provide a suitable name and an expiration period for the key.<br></br><br></br>![Alt text](img/28.png)\\n6. Click **Generate**\\n7. Copy and retain the API key.\\n\\n[^API]: <LinkSvg /><a href=\\"https://qlik.dev/apis\\" target=\\"_blank\\">Qlik APIs</a>"},{"id":"freshservice","metadata":{"permalink":"/RSA/blog/freshservice","source":"@site/blog/collections/freshservice/freshservice.md","title":"Collections - Freshservice","description":"Freshservice is a cloud-based IT service management platform that streamlines and automates IT tasks. It offers a user-friendly interface, ticketing system, asset management, and reporting tools. With its intuitive design, Freshservice enables organizations to efficiently manage their IT services, track incidents, and maintain a well-organized IT infrastructure.Identities \u274c | Accounts \u2714\ufe0f | Groups \u2714\ufe0f | App Roles \u2714\ufe0f | Entitlements \u274c","date":"2023-08-25T00:00:00.000Z","formattedDate":"August 25, 2023","tags":[{"label":"Collections","permalink":"/RSA/blog/tags/collections"},{"label":"REST","permalink":"/RSA/blog/tags/rest"},{"label":"ITSM","permalink":"/RSA/blog/tags/itsm"},{"label":"SaaS","permalink":"/RSA/blog/tags/saa-s"},{"label":"Freshservice","permalink":"/RSA/blog/tags/freshservice"}],"readingTime":32.3,"hasTruncateMarker":true,"authors":[{"name":"Pradeep Kadambar","title":"Author","url":"https://github.com/pradeepkg","image_url":"https://github.com/pradeepkg.png","imageURL":"https://github.com/pradeepkg.png"}],"frontMatter":{"slug":"freshservice","title":"Collections - Freshservice","date":"2023-08-25T00:00:00.000Z","authors":{"name":"Pradeep Kadambar","title":"Author","url":"https://github.com/pradeepkg","image_url":"https://github.com/pradeepkg.png","imageURL":"https://github.com/pradeepkg.png"},"tags":["Collections","REST","ITSM","SaaS","Freshservice"]},"prevItem":{"title":"Collections - Qlik","permalink":"/RSA/blog/qlik"}},"content":"import logoPNG from \'@site/static/img/logos/Freshservice - 180x180.png\';\\nimport LinkSvg from \'../../iconmonstr-link-thin.svg\';\\n\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td width=\\"180\\"><img src={logoPNG}/></td>\\n    <td>Freshservice is a cloud-based IT service management platform that streamlines and automates IT tasks. It offers a user-friendly interface, ticketing system, asset management, and reporting tools. With its intuitive design, Freshservice enables organizations to efficiently manage their IT services, track incidents, and maintain a well-organized IT infrastructure.<br></br><br></br>Identities \u274c | Accounts \u2714\ufe0f | Groups \u2714\ufe0f | App Roles \u2714\ufe0f | Entitlements \u274c</td>\\n  </tr>\\n</table>\\n\\n\x3c!-- truncate --\x3e\\n\\n**Users** are individuals who interact with the Freshservice platform. They can submit tickets, access knowledge articles, and perform various actions based on their assigned roles and permissions. Each user has a unique account tied to their email, and they can be assigned to specific groups or roles.\\n\\n**Groups** are collections of users with similar roles, responsibilities, or access requirements. By grouping users together, you can streamline permissions and ensure that specific information or functionalities are available to the right people. For instance, you might have a \\"Support Team\\" group that has access to support-related features.\\n\\n**Roles** define the level of access and permissions a user or a group of users has within Freshservice. Roles determine what actions users can perform and what information they can view or modify. Freshservice typically offers predefined roles like agents, admins, and requesters, each with distinct sets of privileges.\\n\\n## Table of Contents\\n>\\n- [Application](#application)\\n- [Account Collector](#account-collector)\\n- [Entitlement Collector](#entitlement-collector)\\n- [Application Setup](#application-setup)\\n\\n## Application\\n\\n**Steps**\\n1. Login to RSA G&L console as System Administrator.\\n2. Navigate to **Resources > Application**.\\n3. Click on **Create Application** and select **Other Application**.\\n4. Enter the details as shown below.<br></br>![img](./img/1.png)\\n5. Click **Finish**.\\n---\\n## Account Collector\\nThis section explains the process for configuring an account collector for the Freshservice application. We will use the RSA G&L Generic REST collector [^API] for this purpose.  \\n\\n**Steps**\\n1. Login to RSA G&L console as System Administrator.\\n2. Navigate to **Resources > Applications**.\\n3. Click on **Freshservice**.\\n4. Navigate to **Collectors** tab and click on **Create Account Collector**. Enter the details as shown below.<br></br><br></br>![img](./img/2.png)\\n5. Click **Next** and enter the connection details. Freshservice supports Basic Access Authorization only with API key [^Authentication]. The API key will be configured as user name and you can provide arbitrary password.<br></br><br></br>![img](img/3.png)\\n6. Click **Next**. Select the data types that the collector will be collecting from Freshservice<br></br><br></br>![img](img/4.png)\\n7. Click **Next**. On the **Account Data** page, enter the following configurations.<br></br><br></br>![Alt text](img/5.png)<br></br>![Alt text](img/6.png)<br></br>![Alt text](img/7.png)<br></br>\\n<p align=\\"center\\"></p>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/api/v2/agents</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>AccountId</td>    \\n    <td><code>$.agents[*].email</code></td>\\n  </tr>\\n  <tr>\\n    <td>Id</td>\\n    <td><code>$.agents[*].id</code></td>\\n  </tr>    \\n  <tr>\\n    <td>ExternalID</td>\\n    <td><code>$.agents[*].external_id</code></td>\\n  </tr>    \\n</table>\\n<p></p>\\n8. Click **Next**. On the **Group Data** page, enter the following configurations.<br></br><br></br>![Alt text](img/8.png)<br></br>![Alt text](img/6.png)<br></br>![Alt text](img/9.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/api/v2/groups</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>GroupId</td>    \\n    <td><code>$.groups[*].name</code></td>\\n  </tr>\\n  <tr>\\n    <td>Id</td>\\n    <td><code>$.groups[*].id</code></td>\\n  </tr>    \\n  <tr>\\n    <td>Description</td>\\n    <td><code>$.groups[*].description</code></td>\\n  </tr>    \\n</table>\\n9. Click **Next**. On the **Account Group Membership**\xa0page, enter the following configurations.<br></br><br></br>![Alt text](img/10.png)<br></br>![Alt text](img/11.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/api/v2/groups/$&#123;Id}</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>AccountId</td>    \\n    <td><code>$.group.members.*</code></td>\\n  </tr>    \\n</table>\\n10. Click\xa0**Next**. In the **Map Collector Attributes to Account Attributes**, map the collected account attributes.<br></br><br></br>![Alt text](img/12.png)\\n11. Click **Next**. In the **Map Collector Attributes to Account Mapping Attributes**, map the user reference attribute.<br></br><br></br>![Alt text](img/13.png)\\n12. Click **Next**. In the **Map Collector Attributes to Group Attributes**, map the collected group attributes.<br></br><br></br>![Alt text](img/14.png)\\n13. Click **Next**. In the **User Resolution Rules**, map the user to account.<br></br><br></br>![Alt text](img/15.png)\\n14. Click **Next**. In the **Member Account Resolution Rules**, map the account.<br></br><br></br>![Alt text](img/16.png)\\n\\n:bulb: **Info:**  This value MUST always be mapped to the Account Name for any generic REST collector.\\n\\n15. Click **Finish**. Use the <code>Test</code> function to make sure the configurations are accurate.\\n\\n---\\n## Entitlement Collector\\nThis section explains the process for configuring an entitlement collector to collect roles from Freshservice application. We will use the RSA G&L Generic REST collector for this purpose.\\n\\n**Steps**\\n1. Login to RSA G&L console as AveksaAdmin.\\n2. Navigate to **Resources > Applications**.\\n3. Click on **Freshservice**.\\n4. Navigate to **Collectors** tab and click on ***Create Entitlement Collector***. Enter the details as shown below.<br></br><br></br>![Alt text](img/17.png)\\n5. Click **Next** and enter the connection details as shown in Step 5 of [Account Collector](#freshservice--account-collector).\\n6. Click **Next**. Select the data types that the collector will be collecting from Freshservice.<br></br><br></br>![Alt text](img/18.png)\\n7. Click **Next**. On the **App Role Data** page, enter the following configurations.<br></br><br></br>![Alt text](img/19.png)<br></br>![Alt text](img/6.png)<br></br>![Alt text](img/20.png)<br></br>\\n<table class=\\"table-container\\">\\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request</span></td>  \\n  </tr> \\n  <tr>\\n    <td>Method</td>    \\n    <td><span class=\\"method-get\\">GET</span></td>\\n  </tr>\\n  <tr>\\n    <td>URL</td>\\n    <td><code>/api/v2/roles</code></td>\\n  </tr>  \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Request Headers</span></td>  \\n  </tr>  \\n  <tr>\\n    <td>Accept</td>\\n    <td><code>application/json</code></td>\\n  </tr> \\n  <tr>\\n    <td colspan=\\"2\\"><span class=\\"header-2-text\\">Response Mappings</span></td>  \\n  </tr>       \\n  <tr>\\n    <td>ApplicationRoleId</td>    \\n    <td><code>$.roles[*].name</code></td>\\n  </tr>\\n  <tr>\\n    <td>Id</td>\\n    <td><code>$.roles[*].id</code></td>\\n  </tr>    \\n  <tr>\\n    <td>Description</td>\\n    <td><code>$.roles[*].description</code></td>\\n  </tr>    \\n</table>\\n8. Click **Next**. On the **App-Role Account Membership** collection page, enter the following configurations.<br></br><br></br>![Alt text](img/21.png)<br></br>![Alt text](img/6.png)<br></br>![Alt text](img/22.png)<br></br>\\n9. Click **Next**. In the **Map Collector Attributes to App Role Attributes**, map the collected account attributes.<br></br>\\n10. Click **Next**. In the **Account Evaluation**, map the account collector to account value.<br></br><br></br>![Alt text](img/23.png)\\n11. Click **Next** and then click **Finish**. Use the <code>Test</code> function to make sure the configurations are accurate\\n\\n---\\n## Application Setup\\nThis section explains the process of setting up a service account in Freshservice for use within the collections process.\\n\\n**Steps**\\n1. Login to Freshservice dashboard.\\n2. On the right hand corner, click on **Profile Settings**.<br></br><br></br>![Alt text](img/24.png)\\n3. Solve the captcha and copy the API key.<br></br><br></br>![Alt text](img/25.png)\\n\\n\\n[^API]: <LinkSvg /><a href=\\"https://api.freshservice.com/\\" target=\\"_blank\\">API Reference</a>\\n[^Authentication]: <LinkSvg /><a href=\\"https://api.freshservice.com/#authentication\\" target=\\"_blank\\">Freshservice authentication</a>"}]}')}}]);